joi_block.script:
t1 = (#TemperatureSensor #Bedroom).temperatureSensor_temperature
delay(30 MIN)
t2 = (#TemperatureSensor #Bedroom).temperatureSensor_temperature
diff = t1 - t2
if (diff < 0) {
diff = t2 - t1
}
if (diff >= 3) {
(#Plug #Switch #Bedroom #Heater).switch_on()
}

